import { SPRING_CONFIGS, SPRING_DESCRIPTIONS } from './tokens.js';
import { springToLinear } from './spring-resolver.js';

// Pre-compute spring results at module load time
const SPRING_RESULTS = Object.fromEntries(
  Object.entries(SPRING_CONFIGS).map(([name, { stiffness, damping, mass }]) => {
    const result = springToLinear(stiffness, damping, mass);
    return [name, result];
  })
);

const COLORS = {
  crisp:  '#0055bb',
  gentle: '#007755',
  bouncy: '#cc3300',
};

export default {
  title: 'Motion/Spring',
  parameters: {
    layout: 'fullscreen',
    docs: {
      description: {
        component:
          'Three spring configurations resolved to CSS linear() at story load time. ' +
          'The linear() output is computed from stiffness/damping/mass via the spring-resolver. ' +
          'Click any row to trigger the animation.',
      },
    },
  },
};

