// ---------------------------------------------------------------------------
// Render helper
// ---------------------------------------------------------------------------
function buildRow(name, config) {
  const { stiffness, damping, mass } = config;
  const { css, duration, dampingRatio } = SPRING_RESULTS[name];
  const color = COLORS[name] || '#333';
  const safeId = `spring_${name}`;
  const truncated = css.length > 63 ? css.slice(0, 60) + '...' : css;
  const desc = SPRING_DESCRIPTIONS[name] || '';
  const isUnderdamped = dampingRatio < 1;
  const warningBadge = isUnderdamped
    ? `<div class="warning-badge">dampingRatio ${dampingRatio} — overshoot</div>`
    : '';

  return `
    <div class="row" onclick="triggerSpringAnimation('${safeId}', '${css.replace(/'/g, "\\'")}', ${duration})">
      <div>
        <div class="token-name">spring.config.${name}</div>
      </div>
      <div class="physics-params">
        <div><span class="physics-key">stiffness </span>${stiffness}</div>
        <div><span class="physics-key">damping   </span>${damping}</div>
        <div><span class="physics-key">mass      </span>${mass}</div>
      </div>
      <div>
        <div class="css-output" title="${css}">${truncated}</div>
        ${desc ? `<div style="font-size:11px;color:#888;margin-top:6px;line-height:1.4;">${desc}</div>` : ''}
        ${warningBadge}
      </div>
      <div>
        <div class="settlement">${duration}ms</div>
        <div class="damping-ratio">ζ = ${dampingRatio}</div>
      </div>
      <div class="track">
        <div class="box" id="${safeId}" style="background: ${color};">
          <div class="box-label">${name}</div>
        </div>
      </div>
    </div>
  `;
}

// ---------------------------------------------------------------------------
// Story: All spring configs
// ---------------------------------------------------------------------------
export const AllSprings = {
  name: 'Spring configurations',
  render: () => {
    const rows = Object.entries(SPRING_CONFIGS)
      .map(([name, config]) => buildRow(name, config))
      .join('');

    const el = document.createElement('div');
    el.innerHTML = `
      <style>${baseStyles}</style>
      <div class="page">
        <div class="page-title">Motion / Spring</div>
        <div class="page-subtitle">Spring configurations</div>
        <div class="page-description">
          Three spring configs resolved to CSS <code>linear()</code> at story load time via the spring-resolver.
          The CSS output column shows the first 60 characters of the generated curve.
          Settlement time is computed from physics — not a hardcoded value.
          Click any row to animate using the generated linear() curve.
        </div>
        <div class="header-row">
          <div>Token</div>
          <div>Physics params</div>
          <div>CSS linear() output</div>
          <div>Settlement</div>
          <div>Preview</div>
        </div>
        ${rows}
      </div>
    `;

    el.ownerDocument.defaultView.triggerSpringAnimation = (id, linearCss, durationMs) => {
      const box = el.querySelector(`#${id}`);
      if (!box || box._animating) return;
      box._animating = true;
      box.animate(
        [
          { transform: 'translateX(0px)' },
          { transform: 'translateX(156px)' },
        ],
        {
          duration: durationMs,
          easing: linearCss,
          fill: 'forwards',
        }
      ).onfinish = () => {
        // Return to start with a neutral ease
        box.animate(
          [
            { transform: 'translateX(156px)' },
            { transform: 'translateX(0px)' },
          ],
          {
            duration: 300,
            easing: 'cubic-bezier(0.4, 0, 1, 1)',
            fill: 'forwards',
          }
        ).onfinish = () => {
          box._animating = false;
        };
      };
    };

    return el;
  },
};

// ---------------------------------------------------------------------------
// Story: Vertical comparison (all animate together)
// ---------------------------------------------------------------------------
export const Comparison = {
  name: 'Side-by-side comparison',
  render: () => {
    const entries = Object.entries(SPRING_CONFIGS);

    const columns = entries
      .map(([name, config]) => {
        const { css, duration, dampingRatio } = SPRING_RESULTS[name];
        const color = COLORS[name] || '#333';
        return `
          <div style="display: flex; flex-direction: column; align-items: flex-start; gap: 10px; flex: 1;">
            <div style="font-size: 12px; font-family: monospace; font-weight: 600; color: #333;">${name}</div>
            <div style="font-size: 10px; color: #888;">ζ = ${dampingRatio}</div>
            <div style="font-size: 10px; color: #888;">~${duration}ms</div>
            <div style="width: 60px; height: 240px; background: #f0f0f0; border-radius: 6px; position: relative; overflow: hidden;">
              <div id="vspring_${name}"
                style="width: 60px; height: 60px; background: ${color}; border-radius: 5px;
                       position: absolute; bottom: 0; left: 0; display: flex; align-items: center; justify-content: center;">
                <span style="font-size: 9px; color: #fff; font-weight: 600;">${name}</span>
              </div>
            </div>
          </div>
        `;
      })
      .join('');

    const el = document.createElement('div');
    el.innerHTML = `
      <style>
        * { box-sizing: border-box; margin: 0; padding: 0; }
        body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #f8f8f8; }
        .page { max-width: 900px; margin: 0 auto; padding: 48px 32px; }
        .page-title { font-size: 13px; font-weight: 600; color: #666; text-transform: uppercase; letter-spacing: 0.08em; margin-bottom: 4px; }
        .page-subtitle { font-size: 20px; font-weight: 700; color: #111; margin-bottom: 8px; }
        .page-description { font-size: 14px; color: #555; line-height: 1.5; margin-bottom: 40px; }
        .play-btn { display: inline-block; padding: 8px 20px; background: #111; color: #fff; font-size: 13px; font-weight: 600; border-radius: 6px; cursor: pointer; border: none; margin-bottom: 32px; font-family: inherit; }
        .play-btn:hover { background: #333; }
        .grid { display: flex; gap: 48px; align-items: flex-end; }
      </style>
      <div class="page">
        <div class="page-title">Motion / Spring</div>
        <div class="page-subtitle">Side-by-side comparison</div>
        <div class="page-description">
          All three springs animate simultaneously. Note the settlement time difference and
          the overshoot on "bouncy" (dampingRatio 0.346 — underdamped).
        </div>
        <button class="play-btn" id="playBtn">Play all</button>
        <div class="grid">${columns}</div>
      </div>
    `;

    el.querySelector('#playBtn').addEventListener('click', () => {
      entries.forEach(([name]) => {
        const box = el.querySelector(`#vspring_${name}`);
        if (!box) return;
        const { css, duration } = SPRING_RESULTS[name];
        box.animate(
          [
            { transform: 'translateY(0px)' },
            { transform: 'translateY(-180px)' },
          ],
          {
            duration,
            easing: css,
            fill: 'forwards',
          }
        ).onfinish = () => {
          box.animate(
            [{ transform: 'translateY(-180px)' }, { transform: 'translateY(0px)' }],
            { duration: 400, easing: 'cubic-bezier(0.4,0,1,1)', fill: 'forwards' }
          );
        };
      });
    });

    return el;
  },
};
